+                        .unwrap_or(sqlmodel_core::Value::Null),
+                    thread_id
+                        .clone()
+                        .map(sqlmodel_core::Value::Text)
+                        .unwrap_or(sqlmodel_core::Value::Null),
+                    created_ts
+                        .clone()
+                        .map(sqlmodel_core::Value::Text)
+                        .unwrap_or(sqlmodel_core::Value::Null),
+                    attachment_type
+                        .map(sqlmodel_core::Value::Text)
+                        .unwrap_or(sqlmodel_core::Value::Null),
+                    media_type
+                        .map(sqlmodel_core::Value::Text)
+                        .unwrap_or(sqlmodel_core::Value::Null),
+                    path.map(sqlmodel_core::Value::Text)
+                        .unwrap_or(sqlmodel_core::Value::Null),
